--
-- Table structure for table `sites`
--

DROP TABLE IF EXISTS `sites`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `sites` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `project_name` varchar(150) NOT NULL,
  `location_name` varchar(150) NOT NULL,
  `site_name` varchar(150) NOT NULL,
  `ap_site_code` varchar(50) DEFAULT NULL,
  `isp` varchar(150) NOT NULL,
  `province` varchar(150) NOT NULL,
  `municipality` varchar(150) NOT NULL,
  `status` enum('REBATES','ONGOING','EXPIRED','REMOVED','ACTIVE','SUPPORT') NOT NULL DEFAULT 'ACTIVE',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `created_by` int(11) NOT NULL DEFAULT 1,
  PRIMARY KEY (`id`),
  UNIQUE KEY `ap_site_code` (`ap_site_code`),
  KEY `fk_sites_created_by` (`created_by`),
  KEY `idx_ap_site_code` (`ap_site_code`),
  CONSTRAINT `fk_sites_created_by` FOREIGN KEY (`created_by`) REFERENCES `personnels` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1084 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `sites`
--

