/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER trg_compute_duration
BEFORE UPDATE ON tickets
FOR EACH ROW
BEGIN
    -- If the status is OPEN or IN_PROGRESS, compute duration from created_at to now()
    IF NEW.status IN ('OPEN', 'IN_PROGRESS') THEN
        SET NEW.duration = TIMESTAMPDIFF(MINUTE, NEW.created_at, NOW());
    -- If the status is CLOSED, compute duration from created_at to solved_date
    ELSEIF NEW.status = 'CLOSED' THEN
        SET NEW.duration = TIMESTAMPDIFF(MINUTE, NEW.created_at, NEW.solved_date);
    END IF;
END */;;
DELIMITER ;
