/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER update_ticket_duration
    BEFORE UPDATE ON tickets
    FOR EACH ROW
BEGIN
    IF NEW.status IN ('OPEN', 'IN_PROGRESS') THEN
        SET NEW.duration = TIMESTAMPDIFF(MINUTE, NEW.created_at, NOW());
    ELSEIF NEW.status IN ('RESOLVED', 'CLOSED') THEN
        IF NEW.solved_date IS NOT NULL THEN
            SET NEW.duration = TIMESTAMPDIFF(MINUTE, NEW.created_at, NEW.solved_date);
        END IF;
    END IF;
END */;;
DELIMITER ;
